import {
  successResponse,
  fromNeverthrowError,
  outputAndExit,
  errorResponse,
} from '@/cli/output';

import { bridge, bridgeSchema, type BridgeInput } from '@/operations/bridge';
import { DESCRIPTIONS } from '@/shared/descriptions';
import type { Command } from '@/types';
import { getWalletOrExit } from '../lib/get-wallet-or-exit';

const SURFACE = `cli:${DESCRIPTIONS.bridge.toolNames.cli}`;

export const bridgeCommand: Command<BridgeInput> = async args => {
  const wallets = await getWalletOrExit(args);

  const parsedArgs = bridgeSchema.safeParse(args);

  if (!parsedArgs.success) {
    return outputAndExit(
      errorResponse({
        code: 'INVALID_INPUT',
        message: parsedArgs.error.message,
        surface: SURFACE,
        cause: 'validation',
      }),
      args
    );
  }

  const bridgeResult = await bridge({ ...args, ...parsedArgs.data }, wallets);

  if (bridgeResult.isErr()) {
    return outputAndExit(fromNeverthrowError(bridgeResult), args);
  }

  return outputAndExit(
    successResponse({
      success: true,
    }),
    args
  );
};
